using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public sealed class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public sealed class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public sealed class ModelMetricsResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public sealed class PerClassMetric
{
    public string ClassName { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketModelService
{
    private readonly string _modelPath;
    private readonly string _dataPath;
    private readonly ILogger<TicketModelService> _logger;
    private ModelMetricsResponse? _metrics;

    public ModelMetricsResponse? Metrics => _metrics;

    public TicketModelService(ILogger<TicketModelService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public void TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Text
                .FeaturizeText("SubjectFeatures", nameof(TicketData.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model with {Path}", _dataPath);
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _metrics = new ModelMetricsResponse
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerClassMetrics = metrics.PerClassLogLoss
                .Select((logLoss, i) => new PerClassMetric
                {
                    ClassName = metrics.ConfusionMatrix.PredictedClassesIndicators[i],
                    Precision = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                    Recall = i < metrics.ConfusionMatrix.PerClassRecall.Count
                        ? metrics.ConfusionMatrix.PerClassRecall[i] : 0,
                    F1Score = ComputeF1(
                        i < metrics.ConfusionMatrix.PerClassPrecision.Count
                            ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                        i < metrics.ConfusionMatrix.PerClassRecall.Count
                            ? metrics.ConfusionMatrix.PerClassRecall[i] : 0),
                })
                .ToArray(),
        };

        _logger.LogInformation(
            "Model trained — MacroAccuracy: {Macro:F4}, MicroAccuracy: {Micro:F4}, LogLoss: {LogLoss:F4}",
            _metrics.MacroAccuracy, _metrics.MicroAccuracy, _metrics.LogLoss);

        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }

    public string ModelPath => _modelPath;

    private static double ComputeF1(double precision, double recall) =>
        precision + recall == 0 ? 0 : 2 * precision * recall / (precision + recall);
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _pool;
    private readonly TicketModelService _modelService;

    public TicketsController(
        PredictionEnginePool<TicketData, TicketPrediction> pool,
        TicketModelService modelService)
    {
        _pool = pool;
        _modelService = modelService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _pool.Predict(input);

        string[] labels = ["Billing", "General", "Technical"];
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
            confidence[labels[i]] = prediction.Score[i];

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }

    [HttpGet("metrics")]
    public ActionResult<ModelMetricsResponse> GetMetrics()
    {
        var metrics = _modelService.Metrics;
        if (metrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(metrics);
    }
}

