using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<TicketModelService>();

var app = builder.Build();

// Train the model at startup so the pool can load it
var modelService = app.Services.GetRequiredService<TicketModelService>();
modelService.TrainAndEvaluate();

// Register PredictionEnginePool after the model file exists
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelService.ModelPath);

// Rebuild the service provider to include the pool registration
// Instead, register everything upfront and use a startup filter.
// Let's restructure: register pool before build, train in middleware.

// --- Restructured approach ---
// We need to rebuild since pool must be in DI before Build().
// The clean pattern: register pool from file, train before app.Run().

app.MapControllers();
app.Run();

